// Restored from ref/webview/assets/pierre-dark-BvenaEZa.js
// Also covers current Pierre theme data chunks in ref/webview/assets.
// Pierre theme chunks are kept as inline frozen data because this restore has no local @pierre/theme package surface to import.

export interface PierreThemeDefinition {
  name: string;
  type: "dark" | "light";
  colors: Record<string, string>;
  tokenColors: Array<{
    scope: string | string[];
    settings: Record<string, string>;
  }>;
  semanticTokenColors: Record<string, string>;
}

function parsePierreTheme(themeJson: string): PierreThemeDefinition {
  return Object.freeze(JSON.parse(themeJson) as PierreThemeDefinition);
}

